static const std::string B64C =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
std::string b64dec(const std::string& s) {
    std::string o; int v=0, vb=-8;
    for (unsigned char c : s) {
        if (c=='=' || c=='\n' || c=='\r') continue;
        size_t p = B64C.find(c); if (p == std::string::npos) continue;
        v = (v<<6)+(int)p; vb += 6;
        if (vb >= 0) { o.push_back(char((v>>vb)&0xFF)); vb -= 8; }
    }
    return o;
}

