std::vector<std::string> tok(const std::string& l) {
    std::vector<std::string> v; std::istringstream ss(l); std::string t;
    while (ss >> t) v.push_back(t); return v;
}
bool endsWith(const std::string& s, const std::string& x) {
    return s.size() >= x.size() && s.compare(s.size()-x.size(), x.size(), x) == 0;
}
bool isBlocked(const std::string& c) {
    for (const auto& b : BLOCKED) if (c == b) return true; return false;
}
int execCmd(const std::vector<std::string>& v) {
    std::vector<char*> a;
    for (const auto& t : v) a.push_back(const_cast<char*>(t.c_str()));
    a.push_back(nullptr);
    pid_t p = fork(); if (p < 0) return -1;
    if (p == 0) { execvp(a[0], a.data()); _exit(127); }
    int s; waitpid(p, &s, 0); return WIFEXITED(s) ? WEXITSTATUS(s) : -1;
}

